import React, { useState, useRef, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { getInitials } from "../utils/helpers";

const PAGE_TITLES = {
  "/admin-dashboard": "Admin Dashboard",
  "/volunteer-dashboard": "Volunteer Dashboard",
  "/needs": "Community Needs",
  "/volunteers": "Volunteers",
  "/map": "Map View",
  "/matching": "Smart Match",
  "/submit-need": "Submit Need",
  "/suggest-need": "Suggest a Need",
  "/add-volunteer": "Add Volunteer",
};

export default function Topbar({ user, urgentCount, availableCount, onSeed, seeding, onLogout }) {
  const location = useLocation();
  const navigate = useNavigate();
  const title = PAGE_TITLES[location.pathname] || (location.pathname.startsWith("/task/") ? "Task Details" : "ReliefLink");
  const isAdmin = user?.role === "admin";

  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handler = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <header className="topbar">
      <div className="topbar-left">
        <h2 style={{ fontSize: 20, fontWeight: 700, color: "#1e293b" }}>{title}</h2>
      </div>

      <div className="topbar-right" style={{ display: "flex", gap: 16, alignItems: "center" }}>
        {isAdmin && onSeed && (
          <button className="btn btn-outline btn-sm" onClick={onSeed} disabled={seeding} style={{ fontSize: 11 }}>
            {seeding ? "Seeding..." : "⚡ Seed Sample Data"}
          </button>
        )}

        <div style={{ display: "flex", gap: 8 }}>
          {urgentCount > 0 && (
            <span className="badge" style={{ background: "#fee2e2", color: "#dc2626", fontSize: 11, fontWeight: 600 }}>
              ⚠ {urgentCount} Urgent
            </span>
          )}
          <span className="badge" style={{ background: "#dcfce7", color: "#16a34a", fontSize: 11, fontWeight: 600 }}>
            {availableCount} Available
          </span>
        </div>

        {/* Profile Dropdown */}
        <div ref={dropdownRef} style={{ position: "relative", borderLeft: "1px solid #e2e8f0", paddingLeft: 16, marginLeft: 8 }}>
          <button
            onClick={() => setDropdownOpen((o) => !o)}
            style={{
              display: "flex", alignItems: "center", gap: 6,
              background: "none", border: "none", cursor: "pointer", padding: "4px 6px",
              borderRadius: 8, transition: "background 0.15s",
            }}
            onMouseEnter={(e) => e.currentTarget.style.background = "#f1f5f9"}
            onMouseLeave={(e) => e.currentTarget.style.background = "none"}
          >
            <div style={{
              width: 36, height: 36, borderRadius: "50%",
              background: "linear-gradient(135deg, #166534, #16a34a)",
              color: "#dcfce7", display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 13, fontWeight: 700, flexShrink: 0, userSelect: "none",
            }}>
              {getInitials(user?.name || user?.email || "U")}
            </div>
            <span style={{ fontSize: 10, color: "#94a3b8" }}>▼</span>
          </button>

          {dropdownOpen && (
            <div style={{
              position: "absolute", right: 0, top: "calc(100% + 8px)", minWidth: 200,
              background: "#ffffff", border: "1px solid #e2e8f0",
              borderRadius: 12, boxShadow: "0 8px 24px rgba(0,0,0,0.12)",
              zIndex: 100, overflow: "hidden",
            }}>
              <div style={{ padding: "14px 16px", borderBottom: "1px solid #f1f5f9", background: "#f8fafc" }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: "#1e293b" }}>{user?.name || "User"}</div>
                <div style={{ fontSize: 11, color: "#64748b", marginTop: 2 }}>{user?.email}</div>
                <div style={{ marginTop: 6 }}>
                  <span style={{ fontSize: 10, padding: "2px 8px", borderRadius: 20, background: "#dcfce7", color: "#166534", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>
                    {user?.role}
                  </span>
                </div>
              </div>

              {!isAdmin && (
                <button
                  onClick={() => { navigate("/profile"); setDropdownOpen(false); }}
                  style={{
                    display: "flex", alignItems: "center", gap: 10, width: "100%",
                    padding: "11px 16px", background: "none", border: "none",
                    cursor: "pointer", fontSize: 13, color: "#1e293b", textAlign: "left",
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.background = "#f8fafc"}
                  onMouseLeave={(e) => e.currentTarget.style.background = "none"}
                >
                  <span style={{ fontSize: 16 }}>👤</span> My Profile
                </button>
              )}

              <div style={{ height: 1, background: "#f1f5f9" }} />

              <button
                onClick={() => { onLogout(); setDropdownOpen(false); }}
                style={{
                  display: "flex", alignItems: "center", gap: 10, width: "100%",
                  padding: "11px 16px", background: "none", border: "none",
                  cursor: "pointer", fontSize: 13, color: "#dc2626", textAlign: "left",
                }}
                onMouseEnter={(e) => e.currentTarget.style.background = "#fef2f2"}
                onMouseLeave={(e) => e.currentTarget.style.background = "none"}
              >
                <span style={{ fontSize: 16 }}>🚪</span> Logout
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}
